B.abA=new A.h([B.d,"\uacc4\uc0b0\uae30/\ub3c4\uac10/\ud30c\ud2f0 \uad6c\ucd95 \uc5b4\ub514\uc5d0\uc11c\ub098 \uc0c9\uc774 \ub2e4\ub978 \ud3ec\ucf13\ubaac\uc744 \ucf1c\uace0 \ub04c \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uc6f9\uc740 \uc790\ub3d9\uc73c\ub85c \uc801\uc6a9\ub418\uc9c0\ub9cc, \ubaa8\ubc14\uc77c\uc5d0\uc11c\ub294 \uc774\ubbf8\uc9c0\ud329\uc744 \ubc18\ub4dc\uc2dc \ub2e4\uc2dc \ubc1b\uc544\uc8fc\uc154\uc57c \uc0c9\uc774 \ub2e4\ub978 \uc774\ubbf8\uc9c0\uac00 \ud45c\uc2dc\ub429\ub2c8\ub2e4. \uc2a4\ud0c0\uc77c \ubcc0\uacbd\uacfc \ud329 \uc7ac\ub2e4\uc6b4\ub85c\ub4dc\ub294 \uc624\ub978\ucabd \uc704 \uba54\ub274(\u22ee)\uc758 \ubaac\uc2a4\ud130\ubcfc \uc544\uc774\ucf58\uc5d0\uc11c \uc124\uc815\ud569\ub2c8\ub2e4.",B.f,"Shiny variants are now toggleable everywhere \u2014 calculator, dex, and team builder. The web build picks them up automatically; on mobile you must re-import the sprite pack to see shiny art. Re-download from the Pok\xe9ball entry in the menu (top-right \u22ee).",B.e,"\u8a08\u7b97\u6a5f\u30fb\u56f3\u9451\u30fb\u30d1\u30fc\u30c6\u30a3\u69cb\u7bc9\u306e\u3069\u3053\u3067\u3082\u8272\u9055\u3044\u306b\u5207\u308a\u66ff\u3048\u3089\u308c\u307e\u3059\u3002Web\u7248\u306f\u81ea\u52d5\u53cd\u6620\u3055\u308c\u307e\u3059\u304c\u3001\u30e2\u30d0\u30a4\u30eb\u3067\u306f\u8272\u9055\u3044\u753b\u50cf\u3092\u8868\u793a\u3059\u308b\u305f\u3081\u306b\u30a4\u30e1\u30fc\u30b8\u30d1\u30c3\u30af\u306e\u518d\u30c0\u30a6\u30f3\u30ed\u30fc\u30c9\u304c\u5fc5\u8981\u3067\u3059\u3002\u53f3\u4e0a\u30e1\u30cb\u30e5\u30fc\uff08\u22ee\uff09\u306e\u30e2\u30f3\u30b9\u30bf\u30fc\u30dc\u30fc\u30eb\u304b\u3089\u53d6\u308a\u76f4\u3057\u3066\u304f\u3060\u3055\u3044\u3002"],t.C)
